part of '../app_router.dart';

Future<void> _handleOpenDriverTripNavigationInGoogleMaps(
  BuildContext context, {
  required DriverTripDetailData data,
}) async {
  final approved = await _showGoogleMapsNavigationConfirmDialog(
    context,
    routeName: data.routeName,
  );
  if (!context.mounted || approved != true) {
    return;
  }

  _showInfo(context, 'Google Maps uygulamasi aciliyor...');

  final origin = '${data.startPoint.lat},${data.startPoint.lng}';
  final destination = '${data.endPoint.lat},${data.endPoint.lng}';
  final waypoints = data.stops
      .map((stop) => '${stop.point.lat},${stop.point.lng}')
      .where((value) => value.isNotEmpty)
      .take(8)
      .toList(growable: false);

  final googleNavigationAppUri = Uri.parse(
    'google.navigation:q=$destination&mode=d',
  );
  final googleMapsWebUri = Uri.https(
    'www.google.com',
    '/maps/dir/',
    <String, String>{
      'api': '1',
      'origin': origin,
      'destination': destination,
      if (waypoints.isNotEmpty) 'waypoints': waypoints.join('|'),
      'travelmode': 'driving',
    },
  );

  final opened = await _tryOpenExternalUri(googleNavigationAppUri) ||
      await _tryOpenExternalUri(googleMapsWebUri);
  if (!context.mounted || opened) {
    return;
  }
  _showInfo(context,
