Future<bool?> _showGoogleMapsNavigationConfirmDialog(
  BuildContext context, {
  required String routeName,
}) {
  return showDialog<bool>(
    context: context,
    builder: (dialogContext) {
      return AlertDialog(
        title: const Text('Dis Navigasyon'),
        content: Text(
          'Navigasyon Google Maps uygulamasinda acilacak.\n\nSefer: $routeName',
        ),
        actions: <Widget>[
          TextButton(
            onPressed: () => Navigator.of(dialogContext).pop(false),
            child: const Text('Iptal'),
          ),
          FilledButton(
            onPressed: () => Navigator.of(dialogContext).pop(true),
            child: const Text('Google Maps Ac'),
          ),
        ],
      );
    },
  );
}

