Future<void> _handleSubmitSupportReport(
  BuildContext context, {
  required SupportReportSource source,
  String? routeId,
  String? tripId,
  bool? batteryDegradeModeEnabled,
}) async {
  final user = _authCredentialGateway.currentUser;
  if (user == null) {
    if (context.mounted) {
      _showInfo(context, CoreErrorFeedbackTokens.sessionMissingSignInAgain);
    }
    return;
  }

  final note = await _showSupportReportDialog(context, source: source);
  if (!context.mounted || note == null) {
    return;
  }

  final subject = <String>[
    supportReportSourceToRaw(source),
    _nullableParam(routeId) ?? 'route_none',
    _nullableParam(tripId) ?? 'trip_none',
  ].join('_');
  final idempotencyKey = _buildTripActionIdempotencyKey(
    action: 'support_report',
    subject: subject,
  );

  try {
    final result = await _supportReportService.submit(
      ownerUid: user.uid,
      source: source,
      routeId: _nullableParam(routeId),
      tripId: _nullableParam(tripId),
      userNote: note,
      batteryDegradeModeEnabled: batteryDegradeModeEnabled,
      idempotencyKey: idempotencyKey,
    );
    if (!context.mounted) {
      return;
    }
    switch (result.state) {
      case TripActionSyncState.synced:
        _showInfo(
          context,
          result.reportId == null || result.reportId!.isEmpty
              ? 'Sorun raporu iletildi.'
              : 'Sorun raporu iletildi (ID: ${result.reportId}).',
        );
        return;
      case TripActionSyncState.pendingSync:
