Future<String?> _showSupportReportDialog(
  BuildContext context, {
  required SupportReportSource source,
}) async {
  final textController = TextEditingController();
  String? inlineError;
  final sourceLabel = switch (source) {
    SupportReportSource.settings => 'Ayarlar',
    SupportReportSource.activeTripSync => 'Aktif Sefer',
    SupportReportSource.shakeShortcut => 'Shake Kisayolu',
  };

  try {
    return await showDialog<String>(
      context: context,
      builder: (dialogContext) {
        return StatefulBuilder(
          builder: (context, setDialogState) {
            void submit() {
              final note = textController.text.trim();
              if (note.length > 600) {
                setDialogState(() {
                  inlineError = 'Not en fazla 600 karakter olabilir.';
                });
                return;
              }
              Navigator.of(dialogContext).pop(note);
            }

            return AlertDialog(
              title: const Text('Sorun Bildir'),
              content: Column(
                mainAxisSize: MainAxisSize.min,
                crossAxisAlignment: CrossAxisAlignment.stretch,
                children: <Widget>[
                  Text('Kaynak: $sourceLabel'),
                  const SizedBox(height: 8),
                  TextField(
                    controller: textController,
                    minLines: 3,
                    maxLines: 6,
                    textInputAction: TextInputAction.newline,
                    decoration: InputDecoration(
                      labelText: 'Kisa Not (opsiyonel)',
                      hintText:
                          'Orn: internet gidip geliyor, finishTrip senkron olmadi...',
                      errorText: inlineError,
                    ),
                    onChanged: (_) {
                      if (inlineError == null) {
                        return;
                      }
                      setDialogState(() {
                        inlineError = null;
                      });
                    },
                  ),
                ],
              ),
              actions: <Widget>[
                TextButton(
                  onPressed: () => Navigator.of(dialogContext).pop(),
                  child: const Text('Iptal'),
                ),
                FilledButton(
